css:
section:first-of-type {
    position: relative;
    height: 80vh;
    min-height: 500px;
    display: flex;
    align-items: center;
    justify-content: center;
    background-image: linear-gradient(rgba(49, 35, 30, 0.5), rgba(49, 35, 30, 0.5)), url('images/hero.jpg');
    background-size: cover;
    background-position: center;
    color: #fff;
    text-align: center;
}
.hero-content {
    max-width: 800px;
    padding: 0 20px;
}
.title {
    font-family: var(--font-serif);
    color: #fff;
    font-size: 4.5rem;
    margin-bottom: 10px;
    letter-spacing: 2px;
}
.tagline {
    font-family: var(--font-serif);
    color: #EBE3D5;
    font-size: 1.5rem;
    font-weight: 400;
    margin-bottom: 40px;
    font-style: italic;
}
.btn {
    display: inline-block;
    padding: 14px 32px;
    border-radius: 4px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    font-size: 0.85rem;
    cursor: pointer;
    transition: all 0.3s ease;
}
.btn-primary {
    background-color: var(--color-primary);
    color: #fff;
    border: none;
}
.btn-primary:hover {
    background-color: var(--color-primary-hover);
    color: #fff;
    transform: translateY(-2px);
}
.about-content {
    max-width: 700px;
    margin: 0 auto;
}
.about-content p {
    font-size: 1.15rem;
}
.visit-info {
    display: flex;
    flex-wrap: wrap;
    gap: 40px;
    justify-content: center;
    max-width: 800px;
    margin: 0 auto;
}
.info-block {
    flex: 1;
    min-width: 250px;
    text-align: center;
    background: var(--color-bg);
    padding: 40px;
    border-radius: 8px;
    border: 1px solid var(--color-border);
}
.info-block h3 {
    font-family: var(--font-sans);
    text-transform: uppercase;
    letter-spacing: 2px;
    font-size: 1.1rem;
    margin-bottom: 20px;
    color: var(--color-primary);
}
.info-block p, .info-block ul {
    font-size: 1.1rem;
    list-style: none;
}
.info-block li {
    margin-bottom: 8px;
}
@media (max-width: 768px) {
    .title {
        font-size: 2.8rem;
    }
    .tagline {
        font-size: 1.1rem;
    }
}
